parser grammar SYsUParser;

options {
  tokenVocab=SYsULexer;
}

@parser::members {
    #include "ASTBuilder.h"
    #include <nlohmann/json.hpp>
    using json = nlohmann::json;

    ASTBuilder astBuilder;

    void printAST(const asg::Node* node) {
        json j = astBuilder.buildJSON(node);
        std::cout << j.dump(2) << std::endl;
    }
}

compilationUnit
    :   translationUnit? EOF
    ;

translationUnit
    :   externalDeclaration+
    ;

externalDeclaration
    :   functionDefinition
    |   declaration
    ;

functionDefinition
    : declarationSpecifiers declarator compoundStatement
    {
        auto func = astBuilder.makeFunction($declarator.ctx, $compoundStatement.ctx);
        printAST(func);
    }
    ;

declaration
    :   declarationSpecifiers initDeclaratorList? Semi
    {
        auto decls = astBuilder.makeDeclaration($declarationSpecifiers.ctx, $initDeclaratorList.ctx);
        for (auto decl : decls) {
            printAST(decl);
        }
    }
    ;

declarationSpecifiers
    :   typeSpecifier+
    ;

typeSpecifier
    :   Int
    |   Void
    ;

declarator
    :   Identifier
    |   declarator LeftBracket RightBracket
