    |   declaration
    ;

statement
    :   compoundStatement
    |   expressionStatement
    |   jumpStatement
    ;

expressionStatement
    :   expression? Semi
    ;

jumpStatement
    :   Return expression? Semi
    ;

expression
    :   assignmentExpression (Comma assignmentExpression)*
    ;

assignmentExpression
    :   logicalOrExpression
    |   unaryExpression Equal assignmentExpression
    ;

logicalOrExpression
    :   logicalAndExpression
    ;

logicalAndExpression
